package kr.gampa.battlegrounds.special; public final class JammerEnergy {private double energy;public JammerEnergy(double energy){if(energy<0)throw new IllegalArgumentException();this.energy=energy;}public double blockBlueZoneDamage(double damage){double blocked=Math.min(energy,Math.max(0,damage));energy-=blocked;return Math.max(0,damage-blocked);}public double energy(){return energy;}}